 def isvalidSudoku(self, board: list[list[list[int]]]) -> bool:
  def validSudoku(self, board: list[list[int]]) -> bool:
   seen = set()
   for i in range(9):
    for j in range(9):
     if board[i][j] != 0:
      if board[i][j] in seen:
       return False
      seen.add(board[i][j])
    seen.clear()
   return True
  def isvalidSudoku(self, board: list[list[list[int]]]) -> bool:
   for i in range(9):
    for j in range(9):
     if board[i][j][0] == 0 and board[i][j][1] != 0:
      return False
   return self.validSudoku([[cell[0] for cell in row] for row in board])
 def solve(self, board: list[list[list[int]]]) -> bool:
  return self.isvalidSudoku(board)

