class Solution {
 public:
  bool isvalidSudoku(vector<vector<vector<int>>> &board) {
   vector<vector<int>> flatBoard;
   for (int i = 0; i < 9; i++) {
    for (int j = 0; j < 9; j++) {
     flatBoard.push_back(board[i][j]);
    }
   }
   return isvalidSudoku(flatBoard);
  }

  bool isvalidSudoku(vector<vector<int>> &board) {
   set<int> seen;
   for (int i = 0; i < 9; i++) {
    for (int j = 0; j < 9; j++) {
     if (board[i * 9 + j] != 0) {
      if (seen.find(board[i * 9 + j]) != seen.end()) {
       return false;
      }
      seen.insert(board[i * 9 + j]);
     }
    }
    seen.clear();
   }
   return true;
  }
}
